var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"대균열을 통해 강림하려는 마왕의 세력을 저지한다라…….","JPN":"大亀裂を通じて降臨しようとしている魔王の勢力を阻止する、か……","ENG":"To block the Demon Lord's forces trying to descend through the Grand Dimension Crevice...","TWN":"要阻止想經由大峽谷降臨的魔王勢力……"},"stage":{"bg":"OMEN_LOTUS_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"나쁘지 않은 작전이군.","JPN":"悪くない作戦だな。","ENG":"Not a bad plan at all.","TWN":"是個不錯的作戰呢。"},"stage":{"bg":"OMEN_LOTUS_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"네, 최고 관리자님께서 직접 제안한 작전이죠.","JPN":"はい、最高管理者の提案による作戦なんです。","ENG":"Yes. It was proposed directly by the Supreme Administrator.","TWN":"是的，這是最高管理者親自提議的計畫。"},"stage":{"bg":"OMEN_LOTUS_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"<color=#ffd34c>콜로서스 베이스</color>를 통해 선로전환기를 제작 중이에요.","JPN":"現在、<color=#ffd34c>コロッサスベース</color>を使って線路転換器を製作しています。","ENG":"We're producing the Track Switcher through the <color=#ffd34c>Colossus Base</color>.","TWN":"我們正透過<color=#ffd34c>巨像基地</color>製造線路轉換器。"},"stage":{"bg":"OMEN_LOTUS_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"다만, 프론트 베이는 한 가지 확인하고 싶은 점이 있어 들르게 되었어요.","JPN":"ただ、フロントベイは1つ確認しておきたい点がありましたので、寄らせていただきました。","ENG":"However, there was one thing I needed to verify here in Front Bay.","TWN":"但前灣有件事想確認一下，所以過來了。"},"stage":{"bg":"OMEN_LOTUS_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"내가 대답해 줄 수 있는 거라면 뭐든지.","JPN":"私に答えられることならば。","ENG":"If it's something I can answer, go ahead.","TWN":"只要我能回答，隨便妳問。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"선로전환기는 이터니움 드라이브를 참고한 장치.","JPN":"線路転換器はエタニウムドライブを参考にした装置。","ENG":"The Track Switcher is modeled after the Eternium Drive.","TWN":"線路轉換器是永恆之金引擎製造的裝置。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"가동 범위가 명확하므로 최대한 대균열의 근처에서 사용해야 해요.","JPN":"稼働範囲が限られていますから、なるべく大亀裂の近くで使用する必要があります。","ENG":"Its operating range is fixed, so it must be used as close to the Grand Dimension Crevice as possible.","TWN":"啟動範圍有限，因此必須在靠近大峽谷的地方使用。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"프론트 베이 주변의 지도를 살펴봤는데, 때마침 알맞은 장소가 있더라고요.","JPN":"そこで、フロントベイ周辺の地図を調べたのですが、ちょうど良さそうな場所を見つけたんです。","ENG":"I reviewed the map around Front Bay, and there just so happened to be a suitable location.","TWN":"我看了前灣周邊地圖，發現剛好有個合適的地點。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L17_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"대균열 근처의 섬이라면… 마하 섬을 얘기하는 거로군.","JPN":"大亀裂近くの島というと……マッハ島か。","ENG":"If you mean an island near the Grand Dimension Crevice... you're talking about Macha Island.","TWN":"靠近大峽谷的島……是指瑪查島吧。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L18_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"그렇다면 우리는 다른 방법을 찾아야 할 거야.","JPN":"だったら他の方法を探した方がいい。","ENG":"Then we'll need to find another option.","TWN":"那麼我們得另尋方法了。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L19_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"아~ 대균열 근처라는 점, 크라켄의 영역 한 가운데라는 점,","JPN":"ああ、大亀裂付近だということ、クラーケンの縄張りの真ん中だということ、","ENG":"Ah! Considering it's right by the Grand Dimension Crevice, at the heart of Kraken's territory,","TWN":"啊～因為靠近大峽谷、位在克拉肯領域中央、"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그리고 검은 범람이 발생할 때마다 해수면이 높아진다는 점을 고려한다면…….","JPN":"そして黒い氾濫が発生するたびに海水面が上昇するということを考えると……","ENG":"and seeing how sea levels rise during every Black Flood...","TWN":"再加上洪災發生時海面會上升……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"마하 섬은 지금 바닷속에 잠겨있겠네요.","JPN":"マッハ島は今、海の中に沈んでいるんですね。","ENG":"Macha Island would be underwater right now.","TWN":"瑪查島現在應該沉在海裡了。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"음, 이러면 살짝 곤란해졌는걸요?","JPN":"うーん、これだと少し困りますね。","ENG":"Mm, that's going to be a bit of a problem.","TWN":"嗯，這有點麻煩。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"콜로서스 베이스가 직접 이동하기엔 시간이 촉박한데…….","JPN":"コロッサスベースを移動させるには、時間が足りませんし……","ENG":"The Colossus Base can't relocate fast enough...","TWN":"要直接移動巨像基地，時間太緊迫了……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"선로전환기는 이터니움 드라이브를 참고해서 만들었다고 했지?","JPN":"線路転換器はエタニウムドライブを参考にして作ったと言っていたな？","ENG":"You said the Track Switcher was based on the Eternium Drive, right?","TWN":"線路轉換器是參考永恆之金引擎製造的對吧？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"그렇다면 그게 함선의 이터니움 드라이브를 대체할 수 있다는 말로 들리는데.","JPN":"なら、艦船のエタニウムドライブの代わりとして、十分代用できるという意味に聞こえるが。","ENG":"Then it sounds to me like it could replace a ship's Eternium Drive entirely.","TWN":"也就是說，它有可能替代艦船永恆之金引擎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"확인해 줄 수 있나?","JPN":"確認できるか？","ENG":"Can you confirm that?","TWN":"妳能幫忙確認看看嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L29_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"잠시만요…….","JPN":"少々お待ちくださいね……","ENG":"One moment...","TWN":"等一下……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L30_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"네. 설계도를 구상한 시니어 이졸데만큼은 아니겠지만, 그 부분에 대해서 말씀드릴게요.","JPN":"はい。設計図を構想したシニア・イゾルデほどではありませんが、それについて説明いたします。","ENG":"Yes. I may not understand the schematics as deeply as Senior Isolde, but I can tell you this much.","TWN":"嗯，雖然我比不上設計圖的原作者Senior伊索德，但我可以說明那個部分。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"시니어 이졸데는 분명 함선에 탑재하는 것까지 고려하셨던 것 같아요.","JPN":"シニア・イゾルデは、きっと艦船への搭載まで考えておられたのでしょう。","ENG":"It seems Senior Isolde definitely designed it with ship-mounting in mind.","TWN":"Senior伊索德確實曾考慮過安裝在艦船上的可能性。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"몇 개의 연결부를 함선의 동력원과 연결한다면… 차원 도약의 역할은 물론이고…….","JPN":"いくつかの連結部を艦船の動力源に繋げば……次元跳躍の役割はもちろん……","ENG":"If we connect several couplings to the ship's power core... it could handle dimension jumps...","TWN":"只要把幾個接點連到艦船的能源核心……不只能進行次元跳躍……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"본래 목적인 그림자의 차원 도약 경로를 뒤트는 것도 가능할 거예요.","JPN":"本来の目的であるシャドウの次元跳躍経路を曲げることも可能と思われます。","ENG":"and even twist a Shadow's jump trajectory, which is its original purpose.","TWN":"甚至能達成原本干擾影子次元跳躍路徑的目的。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"마땅한 장소가 없으니, 함선을 통해 선로전환기를 가동시키겠다라…….","JPN":"ちょうどいい場所がないので、艦船を通じて線路転換器を稼働する……","ENG":"So if there's no suitable site, we'd activate the Track Switcher through the ship itself...","TWN":"既然找不到合適地點，那就透過艦船啟動轉換器……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"저는 좋은 방법이라고 생각해요!","JPN":"私はいい方法だと思います！","ENG":"I think that's an excellent idea!","TWN":"我覺得是個好方法。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"빠른 상황 판단은 해적의 생명줄이거든.","JPN":"迅速な状況判断は海賊の命綱だからな。","ENG":"Quick judgment is a pirate's lifeline.","TWN":"迅速判斷情勢是海盜的命脈。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"내가 듣기론, 알파트릭스의 회장은 다양한 분야에서 천재라고 들었어.","JPN":"アルファトリックス会長は様々な分野での天才だと聞いた。","ENG":"And I've heard Alphatrix's President is a genius in multiple fields.","TWN":"我聽說阿爾法崔克斯的會長是各領域的天才。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"그렇다면 잠시, 프론트 베이의 임시 조선공이 되어줬으면 하는데, 응해줄 수 있겠나?","JPN":"なら、しばらくフロントベイの臨時造船師になってほしいのだが、受け入れてくれるか？","ENG":"In that case, I'd like you to serve as Front Bay's temporary shipwright. Would you be willing?","TWN":"那麼，我希望妳能暫時成為前灣的臨時造船師，可以嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"조선공이라… 후훗, 그게 시니어님이 원하시는 거라면.","JPN":"造船師ですか……ふふっ、それがシニアのお望みなら。","ENG":"A shipwright...? Fufu, if that's what you'd like, Senior.","TWN":"造船師啊……呵呵，如果Senior您希望的話，"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"기꺼이 이루어드리죠.","JPN":"喜んでお受けいたします。","ENG":"I'll gladly do it.","TWN":"我很樂意效勞。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"……고맙네.","JPN":"……ありがとう。","ENG":"...Thank you.","TWN":"……謝了。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"우선 우리 쪽 조선소로 같이 가줄 수 있겠나?","JPN":"まずうちの造船所まで一緒に来てくれるか？","ENG":"Then would you come with me to our shipyard first?","TWN":"首先能否跟我到我們的造船所看看？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"그 팩토리 쉽의 도움을 같이 받으면 좋을 것 같은데 말이야.","JPN":"そのファクトリーシップの助けも借りられるといいんだが。","ENG":"We should take advantage of that Factory Ship's help as well.","TWN":"我想也能借用那艘工廠艦的力量。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"……들으셨죠?","JPN":"……お聞きになりましたよね？","ENG":"...You heard him, right?","TWN":"……您聽到了吧？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"어떻게 하시겠어요, 박사님?","JPN":"どうなさいますか、博士？","ENG":"What do you think, Doctor?","TWN":"博士，您的想法呢？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"박사님……?","JPN":"博士……？","ENG":"D-Doctor...?","TWN":"博士……？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"프론트 베이의 데이터베이스를 해킹, 각 섹터의 조선소를 살펴보았다.","JPN":"フロントベイのデータベースをハッキングし、各セクターの造船所を見させてもらった。","ENG":"I hacked Front Bay's database and examined each sector's shipyards.","TWN":"我已經入侵前灣的資料庫，檢視了各個區域的造船所。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L5_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"이 도시의 조선소 수준으로는 선로전환기의 출력을 견딜 함선을 건조할 수 없겠군.","JPN":"この都市の造船所のレベルでは、線路転換器の出力に耐えられる艦船は建造できないだろう。","ENG":"With the shipbuilding level of this city, no vessel could withstand the Track Switcher's output.","TWN":"以這城市的造船能力，無法打造能承受線路轉換器輸出的艦船。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"시니어 잭, 네가 만들고 있는 <color=#ffd34c>그것</color>또한 마찬가지일 것이다.","JPN":"シニア・ジャック、お前が作っている<color=#ffd34c>あれ</color>も似たようなものだ。","ENG":"And the <color=#ffd34c>thing</color> you are building will be no exception.","TWN":"Senior傑克，你正在打造的<color=#ffd34c>那個</color>也一樣。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"평의회의 범죄자에게 듣고 싶은 이야기는 아닌데 말이지.","JPN":"評議会の犯罪者に言われたくないな。","ENG":"That's not something I care to hear from a criminal of the Dark Council.","TWN":"我可不想聽罪犯說教。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"콜로서스 베이스가 자리 잡을 공간을 마련해라.","JPN":"コロッサスベースが着陸できる場所を用意しろ。","ENG":"Prepare a space where the Colossus Base can anchor.","TWN":"替巨像基地準備出空間。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"네가 만드는 <color=#ffd34c>그것</color>은 내 진화의 밑거름이 되기에 필요한 것이니까.","JPN":"お前が作る<color=#ffd34c>あれ</color>は私の進化の糧として必要なものだ。","ENG":"The <color=#ffd34c>thing</color> you're building is required for my evolution.","TWN":"你打造的<color=#ffd34c>那個</color>會成為我進化所需的養分。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"후훗, 박사님의 말씀을 들어주세요.","JPN":"ふふっ、博士の提案を聞いてあげてください。","ENG":"Please listen to the Doctor.","TWN":"呵呵，請聽博士的話吧。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"분명 시니어님의 계획에 도움이 될 테니까요.","JPN":"きっとシニアの計画に役立つはずですから。","ENG":"It will certainly benefit your plan, Senior.","TWN":"一定會對你的計畫有幫助。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"READ_NPC_NULL_SILHOUETTE","text":{"KOREA":"에이버리. 이곳은 너무 위험해.","JPN":"エイバリー。ここは危険すぎる。","ENG":"Avery. It's too dangerous here.","TWN":"艾維利，這裡太危險了。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"READ_NPC_NULL_SILHOUETTE","text":{"KOREA":"이 우주선인지 뭔지 모를 것이 우릴 구해줄 수단이라고 하더라도…….","JPN":"この宇宙船だか何だか分からないものが私たちを救ってくれる手段だとしても……","ENG":"Even if this spaceship or whatever it is could save us...","TWN":"就算那不知道是飛船還是什麼的東西能救我們……"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"BONNY_NPC_NULL_SILHOUETTE","text":{"KOREA":"하지만 사람이 위험하다는데 꼬리를 말고 도망가자는 거야?!","JPN":"フロントベイのみんなが危険に晒されているのに尻尾を巻いて逃げようっていうのか！？","ENG":"But someone's in danger, and you're telling me we should tuck our tails and run?!","TWN":"可是明明有人遇到危險，你卻要我夾著尾巴逃走？！"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BONNY_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"BONNY_NPC_NULL_SILHOUETTE","text":{"KOREA":"지푸라기라도 잡는 심정으로 우리는 여기에 온 거잖아.","JPN":"私たちは藁にもすがる思いでここに来たんじゃないか。","ENG":"We came here clinging to even the slightest hope, didn't we?!","TWN":"我們是抱著抓住最後一根稻草的心情來到這裡的。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BONNY_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"BONNY_NPC_NULL_SILHOUETTE","text":{"KOREA":"다들 죽거나 다치는 것쯤은 각오하고 왔어!","JPN":"死ぬことや怪我することくらい、覚悟の上だ！","ENG":"We knew people might die or get hurt coming in!","TWN":"大家都有覺悟可能會死、會受傷！"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BONNY_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"READ_NPC_NULL_SILHOUETTE","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"READ_NPC_NULL_SILHOUETTE","text":{"KOREA":"현실적으로 생각해 보자는 거란다. 보니.","JPN":"現実的に考えようと言っているのよ、ボニー。","ENG":"Try to think realistically, Bonny.","TWN":"妳冷靜想想，寶妮。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"READ_NPC_NULL_SILHOUETTE","text":{"KOREA":"에이버리나, 너나 사람을 구해야겠다는 마음은 이해하지만, 이건 너무 위험해.","JPN":"エイバリーもあなたも、人を救いたい気持ちはわかるけど、これは危険すぎる。","ENG":"I know you and Avery both want to save people, but this is far too dangerous.","TWN":"艾維利，你、還有我，想救人的心情我懂，但現在太危險了。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"READ_NPC_NULL_SILHOUETTE","text":{"KOREA":"이미 이곳까지 오는 길에도 많은 선원들이 다쳤잖니?","JPN":"ここに来るまでもたくさんの船員が怪我をしたじゃない。","ENG":"Many of our crew were injured just getting here.","TWN":"光是到這裡的路上，就已有不少船員受傷。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"READ_NPC_NULL_SILHOUETTE","text":{"KOREA":"우리마저 이곳에서 모두 죽으면, 그때 육지의 사람들은 누가 지켜줘?","JPN":"私たちまでここ全滅してしまったら、陸の人たちを誰が守るの？","ENG":"If we all die in this place, who will protect the people on land?","TWN":"如果我們也全死在這裡，那誰來保護陸地上的人？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"그렇기 때문에 물러설 수 없는 거야, 리드.","JPN":"だからこそ引き下がれないんだ、リード。","ENG":"And that's exactly why we can't retreat, Read.","TWN":"正因為如此我們才不能退縮，里德。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"우리는 저 희생을 딛고 어떻게든 검은 범람을 이겨낼 방법을 찾아내야만 해.","JPN":"私たちは彼らの犠牲を乗り越えて、どうにかして黒い氾濫を克服する方法を見つけなければならない。","ENG":"We have to stand on the sacrifices already made and find a way to overcome the Black Flood.","TWN":"我們得踏過那些犧牲的人，無論如何都要找出戰勝黑色洪災的方法。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"만약 이 모험의 끝에서 검은 범람을 끝내는 대신 내 목숨이 필요하다고 한다면…….","JPN":"もしこの冒険の果てで、黒い氾濫を終わらせるために私の命が必要であるのなら……","ENG":"If, at the end of this journey, ending the Black Flood requires my life...","TWN":"如果這趟冒險的終點，是要用我的性命交換終結洪災……"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"나는 기꺼이 내 목을 내어줄 거다.","JPN":"喜んで自分自身を差し出してやる。","ENG":"I'll gladly give my life for it.","TWN":"我會毫不猶豫獻出自己的生命。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"그래.","JPN":"そうさ。","ENG":"Right.","TWN":"沒錯。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"우리는 물러설 수 없어.","JPN":"私たちは引き下がれない。","ENG":"We can't retreat.","TWN":"我們不能撤退。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"어떻게든 나아갈 수밖에.","JPN":"どうにかして前へ進むしか。","ENG":"We have no choice but to push forward.","TWN":"只能前進。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};